import { Router } from "express";
import jwt from "jsonwebtoken";
import { users, nextId } from "../db.js";
import { JWT_SECRET } from "../middleware/auth.js";

const router = Router();

// Simple deterministic hash — no external deps needed
function hashPassword(password: string): string {
  let hash = 5381;
  for (let i = 0; i < password.length; i++) {
    hash = ((hash << 5) + hash) ^ password.charCodeAt(i);
    hash = hash | 0; // keep it 32-bit
  }
  return (hash >>> 0).toString(16); // unsigned hex string
}

// POST /auth/register — create a new user and return a JWT
router.post("/register", (req, res) => {
  const { username, email, password } = req.body;
  if (!username || !email || !password) {
    res.status(400).json({ error: "username, email, and password are required" });
    return;
  }
  if (users.find((u) => u.username === username)) {
    res.status(409).json({ error: "Username already taken" });
    return;
  }
  const newUser = {
    id: nextId(users),
    username,
    email,
    password: hashPassword(password),
  };
  users.push(newUser);
  const token = jwt.sign(
    { userId: newUser.id, username: newUser.username },
    JWT_SECRET,
    { expiresIn: "1h" }
  );
  res.status(201).json({
    token,
    user: { id: newUser.id, username: newUser.username, email: newUser.email },
  });
});

// POST /auth/login — verify credentials and return a JWT
router.post("/login", (req, res) => {
  const { username, password } = req.body;
  const user = users.find((u) => u.username === username);
  if (!user || user.password !== hashPassword(password)) {
    res.status(401).json({ error: "Invalid credentials" });
    return;
  }
  const token = jwt.sign(
    { userId: user.id, username: user.username },
    JWT_SECRET,
    { expiresIn: "1h" }
  );
  res.json({ token });
});

export { router as authRouter };

